const balanceData = $('Get Current Balance').first().json;

const currentBalance = Number(balanceData?.data?.current_balance || balanceData?.data?.balance || balanceData?.current_balance || balanceData?.balance || 0);

// Try to get spend data from balance history API
let totalSpendToday = 0;
let historyAvailable = false;
try {
  const historyData = $('Get Balance History').first().json;
  if (historyData && !historyData.error) {
    const history = historyData?.data?.result?.data || historyData?.data || (Array.isArray(historyData) ? historyData : []);
    const todayStr = new Date().toISOString().slice(0, 10);
    const spendEntries = Array.isArray(history) ? history.filter(h => h.type === 'spend' && (h.processed_at || '').startsWith(todayStr)) : [];
    totalSpendToday = spendEntries.reduce((sum, h) => sum + Math.abs(h.amount || 0), 0);
    historyAvailable = true;
  }
} catch (e) {
  // Balance history API not available, try DB fallback
}

// If no history from API, try getting today's spend from ad_stats via previous node
if (!historyAvailable) {
  try {
    const dbSpend = $('Get Today Spend from DB').first().json;
    totalSpendToday = Number(dbSpend?.total_spend || 0);
  } catch (e) {
    // No spend data available
  }
}

// Calculate spend rate
const now = new Date();
const hoursElapsed = now.getHours() + now.getMinutes() / 60;
const spendRatePerHour = hoursElapsed > 0.5 ? totalSpendToday / hoursElapsed : 0;

// Estimate hours remaining
const hoursRemaining = spendRatePerHour > 0 ? currentBalance / spendRatePerHour : 999;

const minBalanceAlert = Number(10);
let alerts = [];

if (currentBalance < minBalanceAlert) {
  alerts.push({
    type: 'LOW_BALANCE',
    severity: 'critical',
    message: `💰 BALANCE LOW! $${currentBalance.toFixed(2)} remaining (threshold: $${minBalanceAlert})`
  });
}

if (hoursRemaining < 6 && hoursRemaining < 999) {
  alerts.push({
    type: 'BALANCE_RUNNING_OUT',
    severity: 'warning',
    message: `⏰ Balance will run out in ~${hoursRemaining.toFixed(1)} hours at current rate`
  });
}

return [{
  json: {
    balance: Math.round(currentBalance * 100) / 100,
    total_spend_today: Math.round(totalSpendToday * 100) / 100,
    spend_rate_per_hour: Math.round(spendRatePerHour * 10000) / 10000,
    hours_remaining: Math.round(hoursRemaining * 100) / 100,
    hours_elapsed: Math.round(hoursElapsed * 100) / 100,
    history_source: historyAvailable ? 'api' : 'db_fallback',
    alerts: alerts,
    has_alerts: alerts.length > 0,
    collected_at: $now.toISO()
  }
}];

const data = $input.first().json;

let message = `💰 BALANCE WATCHDOG ${$now.toFormat('dd.MM.yyyy HH:mm')}\n\n`;
message += `Balance: $${data.balance}\n`;
message += `Spend today: $${data.total_spend_today}\n`;
message += `Rate: $${data.spend_rate_per_hour}/hour\n`;
message += `Estimated remaining: ${data.hours_remaining}h\n\n`;

if (data.alerts && data.alerts.length > 0) {
  message += `⚠️ ALERTS:\n`;
  data.alerts.forEach(a => {
    message += `${a.message}\n`;
  });
}

return [{ json: { message } }];
